import star from "../../Files/star-svgrepo-com.svg"

function StarRatingByUser({rating,max = 5}) {
  return (
    <div>
      <div style={{ display: "flex", gap: "2px" }}>
        {Array.from({ length: max }, (_, i) => (
          <span key={i} style={{ fontSize: "1rem", color: i < rating ? "gold" : "#ccc" }}>
            <img src={star}/>
          </span>
        ))}
      </div>
    </div>
  );
}

export default StarRatingByUser;
